### 2.3 Service Discovery

```go
// pkg/network/discovery.go
package network

import (
	"context"
	"fmt"
	"sync"
	"time"

	"go.etcd.io/etcd/client/v3"
	"go.etcd.io/etcd/client/v3/concurrency"
)

type ServiceDiscovery struct {
	client     *clientv3
	election   *concurrency.Election
	session    *concurrency.Session
	nodeID     string
	services   map[string]*ServiceEndpoint
	mu         sync.RWMutex
	ctx        context.Context
	cancel     context.CancelFunc
}

type ServiceEndpoint struct {
	Name      string
	NodeID    string
	Address   string
	Port      int
	Metadata  map[string]string
	CreatedAt time.Time
}

func NewServiceDiscovery(etcdEndpoints []string, nodeID string) (*ServiceDiscovery, error) {
	client, err := clientv3.New(clientv3.Config{
		Endpoints:   etcdEndpoints,
		DialTimeout: 5 * time.Second,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to create etcd client: %w", err)
	}

	ctx, cancel := context.WithCancel(context.Background())

	session, err := concurrency.NewSession(client, concurrency.WithContext(ctx))
	if err != nil {
		client.Close()
		cancel()
		return nil, fmt.Errorf("failed to create session: %w", err)
	}

	return &ServiceDiscovery{
		client:   client,
		session:  session,
		nodeID:   nodeID,
		services: make(map[string]*ServiceEndpoint),
		ctx:      ctx,
		cancel:   cancel,
	}, nil
}

func (sd *ServiceDiscovery) Register(serviceName, address string, port int, metadata map[string]string) error {
	endpoint := &ServiceEndpoint{
		Name:      serviceName,
		NodeID:    sd.nodeID,
		Address:   address,
		Port:      port,
		Metadata:  metadata,
		CreatedAt: time.Now(),
	}

	key := fmt.Sprintf("/services/%s/%s", serviceName, sd.nodeID)
	value := endpoint.Marshal()

	// Register with lease for automatic cleanup
	lease, err := sd.client.Grant(sd.ctx, 30)
	if err != nil {
		return fmt.Errorf("failed to create lease: %w", err)
	}

	_, err = sd.client.Put(sd.ctx, key, value, clientv3.WithLease(lease.ID))
	if err != nil {
		return fmt.Errorf("failed to register service: %w", err)
	}

	// Keep lease alive
	go func() {
		ticker := time.NewTicker(20 * time.Second)
		defer ticker.Stop()

		for {
			select {
			case <-sd.ctx.Done():
				return
			case <-ticker.C:
				sd.client.KeepAlive(sd.ctx, lease.ID)
			}
		}
	}()

	sd.mu.Lock()
	sd.services[serviceName] = endpoint
	sd.mu.Unlock()

	return nil
}

func (sd *ServiceDiscovery) Discover(serviceName string) ([]*ServiceEndpoint, error) {
	keyPrefix := fmt.Sprintf("/services/%s/", serviceName)

	resp, err := sd.client.Get(sd.ctx, keyPrefix, clientv3.WithPrefix())
	if err != nil {
		return nil, fmt.Errorf("failed to discover services: %w", err)
	}

	var endpoints []*ServiceEndpoint
	for _, kv := range resp.Kvs {
		endpoint := &ServiceEndpoint{}
		if err := endpoint.Unmarshal(kv.Value); err != nil {
			continue
		}
		endpoints = append(endpoints, endpoint)
	}

	return endpoints, nil
}

func (sd *ServiceDiscovery) Watch(serviceName string, callback func([]*ServiceEndpoint)) {
	watchChan := sd.client.Watch(sd.ctx, fmt.Sprintf("/services/%s/", serviceName), clientv3.WithPrefix())

	go func() {
		for {
			select {
			case <-sd.ctx.Done():
				return
			case resp := <-watchChan:
				endpoints, _ := sd.Discover(serviceName)
				callback(endpoints)
			}
		}
	}()
}

func (e *ServiceEndpoint) Marshal() string {
	return fmt.Sprintf("%s:%d:%s", e.Address, e.Port, e.NodeID)
}

func (e *ServiceEndpoint) Unmarshal(data string) error {
	// Simplified parsing - in production use proper serialization
	fmt.Sscanf(data, "%s:%d:%s", &e.Address, &e.Port, &e.NodeID)
	return nil
}
