## 3. Consensus Algorithms

### 3.1 Raft Implementation for Apple Silicon

Raft is well-suited for Apple Silicon clusters due to its simplicity and leader-based nature. Here's an optimized implementation:

```go
// pkg/consensus/raft.go
package consensus

import (
	"context"
	"fmt"
	"log"
	"net"
	"os"
	"sync"
	"time"

	"go.etcd.io/etcd/raft/v3"
	"go.etcd.io/etcd/raft/v3/confchange"
	"go.etcd.io/etcd/raft/v3/raftpb"
	"go.etcd.io/etcd/raft/v3/wal"
)

type RaftConfig struct {
	NodeID     string
	ClusterID  string
	DataDir    string
	Peers      []string
	ListenAddr string
}

type RaftNode struct {
	config     *RaftConfig
	raftNode   raft.Node
	storage    raft.Storage
	wal        *wal.WAL
	transport  *RaftTransport

	// Apple Silicon specific optimizations
	mu         sync.RWMutex
	applyChan  chan raftpb.Message
	snapshotCh chan *raftpb.Snapshot

	// Metrics
	metrics    *ConsensusMetrics
}

type ConsensusMetrics struct {
	LeaderChanges    int64
	Term             int64
	CommitIndex      int64
	AppliedIndex     int64
	PendingProposals int64
}

func NewRaftNode(config RaftConfig) (*RaftNode, error) {
	// Create data directory
	if err := os.MkdirAll(config.DataDir, 0755); err != nil {
		return nil, fmt.Errorf("failed to create data directory: %w", err)
	}

	// Initialize storage
	storage := raft.NewMemoryStorage()

	// Initialize WAL
	walPath := fmt.Sprintf("%s/wal", config.DataDir)
	wal, err := wal.Create(walPath, nil)
	if err != nil {
		return nil, fmt.Errorf("failed to create WAL: %w", err)
	}

	// Create peer map
	peers := make(map[uint64]string)
	for i, peer := range config.Peers {
		peers[uint64(i+1)] = peer
	}

	// Configuration
	raftConfig := &raft.Config{
		ID:              uint64(hashNodeID(config.NodeID)),
		ElectionTick:    10,
		HeartbeatTick:   1,
		Storage:         storage,
		MaxSizePerMsg:   1024 * 1024, // 1MB
		MaxInflightMsgs: 256,
		// Apple Silicon optimization: larger batch size
		MaxCommittedSizePerReady: 64 * 1024 * 1024, // 64MB
	}

	// Create Raft node
	var raftNode raft.Node
	if len(peers) > 0 {
		raftNode = raft.StartNode(raftConfig, []raft.Peer{})
	} else {
		// Single node or joining cluster
		raftNode = raft.StartNode(raftConfig, nil)
	}

	transport, err := NewRaftTransport(config.ListenAddr)
	if err != nil {
		return nil, err
	}

	return &RaftNode{
		config:     &config,
		raftNode:   raftNode,
		storage:    storage,
		wal:        wal,
		transport:  transport,
		applyChan:  make(chan raftpb.Message, 1024),
		snapshotCh: make(chan *raftpb.Snapshot, 10),
		metrics:    &ConsensusMetrics{},
	}, nil
}

func (r *RaftNode) Start() error {
	// Start WAL
	if err := r.wal.Start(); err != nil {
		return fmt.Errorf("failed to start WAL: %w", err)
	}

	// Start transport
	if err := r.transport.Start(); err != nil {
		return fmt.Errorf("failed to start transport: %w", err)
	}

	// Start main loop
	go r.run()

	return nil
}

func (r *RaftNode) run() {
	ticker := time.NewTicker(100 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			r.raftNode.Tick()

		case rd := <-r.raftNode.Ready():
			// Save to WAL
			if rd.Snapshot != nil {
				if err := r.saveSnapshot(rd.Snapshot); err != nil {
					log.Printf("Error saving snapshot: %v", err)
				}
			}

			if len(rd.Entries) > 0 {
				if err := r.wal.Save(rd.Entries, nil); err != nil {
					log.Printf("Error saving entries: %v", err)
				}
			}

			if rd.HardState.Term != 0 || rd.HardState.Vote != 0 || rd.HardState.Commit != 0 {
				if err := r.wal.Save(rd.HardState, nil); err != nil {
					log.Printf("Error saving hard state: %v", err)
				}
			}

			// Send messages
			for _, msg := range rd.Messages {
				r.transport.Send(msg)
			}

			// Apply to state machine
			if len(rd.CommittedEntries) > 0 {
				r.applyToStateMachine(rd.CommittedEntries)
			}

			// Update Raft node
			r.raftNode.Advance()

		case snapshot := <-r.snapshotCh:
			if err := r.storage.CreateSnapshot(
				snapshot.Metadata.Index,
				snapshot.Metadata.Term,
				snapshot,
			); err != nil {
				log.Printf("Error creating snapshot: %v", err)
			}
		}
	}
}

func (r *RaftNode) applyToStateMachine(entries []raftpb.Entry) {
	for _, entry := range entries {
		switch entry.Type {
		case raftpb.EntryNormal:
			if len(entry.Data) > 0 {
				// Apply command
				select {
				case r.applyChan <- entry:
				default:
					log.Printf("Apply channel full, dropping entry")
				}
			}
		case raftpb.EntryConfChange:
			var cc raftpb.ConfChange
			if err := cc.Unmarshal(entry.Data); err != nil {
				log.Printf("Error unmarshaling conf change: %v", err)
				continue
			}

			r.raftNode.ApplyConfChange(cc)
		}

		r.metrics.AppliedIndex = entry.Index
	}
}

func (r *RaftNode) Propose(ctx context.Context, data []byte) error {
	return r.raftNode.Propose(ctx, data)
}

func (r *RaftNode) IsLeader() bool {
	r.mu.RLock()
	defer r.mu.RUnlock()

	status := r.raftNode.Status()
	return status.Lead == status.ID
}

func (r *RaftNode) Stop() error {
	r.raftNode.Stop()
	r.transport.Stop()
	r.wal.Close()
	return nil
}

func (r *RaftNode) saveSnapshot(snapshot *raftpb.Snapshot) error {
	snapPath := fmt.Sprintf("%s/snap-%d.bin", r.config.DataDir, snapshot.Metadata.Index)

	file, err := os.Create(snapPath)
	if err != nil {
		return err
	}
	defer file.Close()

	data, err := snapshot.Marshal()
	if err != nil {
		return err
	}

	_, err = file.Write(data)
	return err
}

// Transport for Raft messages
type RaftTransport struct {
	listener   net.Listener
	conns      map[uint64]net.Conn
	mu         sync.RWMutex
	ctx        context.Context
	cancel     context.CancelFunc
}

func NewRaftTransport(addr string) (*RaftTransport, error) {
	listener, err := net.Listen("tcp", addr)
	if err != nil {
		return nil, err
	}

	ctx, cancel := context.WithCancel(context.Background())

	return &RaftTransport{
		listener: listener,
		conns:    make(map[uint64]net.Conn),
		ctx:      ctx,
		cancel:   cancel,
	}, nil
}

func (t *RaftTransport) Start() error {
	go t.acceptConnections()
	return nil
}

func (t *RaftTransport) acceptConnections() {
	for {
		conn, err := t.listener.Accept()
		if err != nil {
			select {
			case <-t.ctx.Done():
				return
			default:
				log.Printf("Error accepting connection: %v", err)
			}
		}

		go t.handleConnection(conn)
	}
}

func (t *RaftTransport) handleConnection(conn net.Conn) {
	// Handle incoming Raft messages
	buf := make([]byte, 65536)
	for {
		select {
		case <-t.ctx.Done():
			conn.Close()
			return
		default:
			n, err := conn.Read(buf)
			if err != nil {
				return
			}

			var msg raftpb.Message
			if err := msg.Unmarshal(buf[:n]); err != nil {
				log.Printf("Error unmarshaling message: %v", err)
				continue
			}

			// Process message
			_ = msg
		}
	}
}

func (t *RaftTransport) Send(msg raftpb.Message) {
	// Implementation for sending messages to other nodes
	_ = msg
}

