	c.commitIndex.WithLabelValues(nodeID).Set(float64(metrics.CommitIndex))
	c.appliedIndex.WithLabelValues(nodeID).Set(float64(metrics.AppliedIndex))
	c.pendingProposals.WithLabelValues(nodeID).Set(float64(metrics.PendingProposals))
}

